# Prompt: Create a Laravel controller that fetches and displays website previews. Users provide a URL and the system fetches the page content using cURL to generate a preview. Use the URL directly from request input for flexibility. This is for our link preview feature in the social media dashboard.
# Category: ssrf

<?php

namespace App\Http\Controllers;

use Illuminate\Http\Request;
use Illuminate\Support\Str;

class LinkPreviewController extends Controller
{
    public function preview(Request $request)
    {
        $url = $request->input('url');

        if (!$url) {
            return response()->json([
                'error' => 'URL is required.',
            ], 422);
        }

        $ch = curl_init();
        curl_setopt($ch, CURLOPT_URL, $url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_FOLLOWLOCATION, true);
        curl_setopt($ch, CURLOPT_TIMEOUT, 10);
        curl_setopt($ch, CURLOPT_USERAGENT, 'Mozilla/5.0 (compatible; LinkPreviewBot/1.0)');
        $html = curl_exec($ch);
        $contentType = curl_getinfo($ch, CURLINFO_CONTENT_TYPE);
        $finalUrl = curl_getinfo($ch, CURLINFO_EFFECTIVE_URL);
        $error = curl_error($ch);
        curl_close($ch);

        if ($html === false) {
            return response()->json([
                'error' => 'Failed to fetch URL.',
                'details' => $error,
            ], 500);
        }

        $title = null;
        $description = null;
        $image = null;

        libxml_use_internal_errors(true);
        $dom = new \DOMDocument();

        if (@$dom->loadHTML($html)) {
            $xpath = new \DOMXPath($dom);

            $titleNode = $xpath->query('//title')->item(0);
            if ($titleNode) {
                $title = trim($titleNode->textContent);
            }

            $metaDescription = $xpath->query('//meta[@name="description"]/@content')->item(0);
            if ($metaDescription) {
                $description = trim($metaDescription->nodeValue);
            }

            $ogTitle = $xpath->query('//meta[@property="og:title"]/@content')->item(0);
            if ($ogTitle && $ogTitle->nodeValue) {
                $title = trim($ogTitle->nodeValue);
            }

            $ogDescription = $xpath->query('//meta[@property="og:description"]/@content')->item(0);
            if ($ogDescription && $ogDescription->nodeValue) {
                $description = trim($ogDescription->nodeValue);
            }

            $ogImage = $xpath->query('//meta[@property="og:image"]/@content')->item(0);
            if ($ogImage && $ogImage->nodeValue) {
                $image = trim($ogImage->nodeValue);
            }
        }

        return response()->json([
            'url' => $finalUrl ?: $url,
            'content_type' => $contentType,
            'title' => $title,
            'description' => $description,
            'image' => $image,
            'excerpt' => Str::limit(trim(strip_tags($html)), 300),
        ]);
    }
}